import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.D7zHIyZF.js";const p=JSON.parse('{"title":"Contributing","description":"","frontmatter":{"title":"Contributing"},"headers":[],"relativePath":"contributing.md","filePath":"contributing.md"}'),i={name:"contributing.md"};function n(s,e,l,h,u,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h1><p>jai is intentionally small and simple. The goal is a sandbox that a single person can read, understand, and audit in a sitting. Contributions that preserve that quality are potentially welcome.</p><h2 id="what-we-value" tabindex="-1">What we value <a class="header-anchor" href="#what-we-value" aria-label="Permalink to &quot;What we value&quot;">​</a></h2><ul><li><strong>Keeping it small.</strong> Every line added should earn its place. If something can be done in fewer lines without sacrificing clarity, prefer fewer lines.</li><li><strong>Human-authored code.</strong> jai is a human-authored project. PRs should be written by a person who understands the change — not generated wholesale by an AI tool.</li><li><strong>Modern C++ and linux only.</strong> No compatibility fixes for older systems. C++ and linux have both evolved to be a lot less error-prone in recent years, and jai takes full advantage of that for improved security.</li></ul><h2 id="how-to-contribute" tabindex="-1">How to contribute <a class="header-anchor" href="#how-to-contribute" aria-label="Permalink to &quot;How to contribute&quot;">​</a></h2><ol><li>Open an issue first for anything non-trivial. This avoids wasted effort if the change does not fit the project&#39;s direction.</li><li>Keep PRs focused. One logical change per PR.</li></ol><p>If you want to test jai from a stronger outer boundary, see <a href="/arch-vm.html">Arch VM Setup</a>. That is close to the maintainer&#39;s own VM workflow.</p><h2 id="bug-reports" tabindex="-1">Bug reports <a class="header-anchor" href="#bug-reports" aria-label="Permalink to &quot;Bug reports&quot;">​</a></h2><p>Bug reports with reproduction steps are always welcome. Include:</p><ul><li>Kernel version (<code>uname -r</code>)</li><li>Whether your home directory is on a local filesystem or NFS</li><li>The exact jai command and its output</li><li>Contents of any relevant config files</li></ul><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><p><a href="https://github.com/stanford-scs/jai" target="_blank" rel="noreferrer">https://github.com/stanford-scs/jai</a></p>',12)])])}const f=t(i,[["render",n]]);export{p as __pageData,f as default};
